import React from 'react';

const entries = [
  {
    degree: 'BS Information Technology',
    school: 'University',
    year: '2023–Present',
  },
];

const Education = () => (
  <section
    id="Education"
    className="min-h-screen flex flex-col items-center py-24"
    style={{ background: '#0a192f', fontFamily: "'Orbitron', sans-serif" }}
  >
    <h1 className="text-4xl text-white mb-12 font-bold">Education</h1>

    <div className="max-w-2xl w-full flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="p-6 rounded-xl"
          style={{ background: '#f8f9fa', borderLeft: '5px solid #0d6efd' }}
        >
          <h3 style={{ color: '#0b1f3a' }}>{e.degree}</h3>
          <p style={{ color: '#555' }}>{e.school}</p>
          <p style={{ color: '#777' }}>{e.year}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Education;
